#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int dp[2000001][2000001];

int main() {
    int p, q, c, M;
    scanf("%d %d %d %d", &p, &q, &c, &M);
    int g[M], b[M];
    for (int i = 0; i < M; i++) {
        scanf("%d %d", &g[i], &b[i]);
    }
    dp[0][0] = 1;
    for (int i = 0; i <= p; i++) {
        for (int j = 0; j <= q; j++) {
            if (i > 0) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
            }
            if (j > 0 && i * 111 - j * 111 > c) {
                dp[i][j] = (dp[i][j] + dp[i][j - 1]) % MOD;
            }
            for (int k = 0; k < M; k++) {
                if (i == g[k] && j == b[k]) {
                    dp[i][j] = 0;
                }
            }
        }
    }
    printf("%d\n", dp[p][q]);
    return 0;
}

